module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend, divisor, quotient, remainder;

    always @* begin
        dividend = A;
        divisor = {8'b0, B};
        quotient = 16'b0;
        remainder = 16'b0;

        if (dividend >= divisor) begin
            quotient = 16'h1;
            remainder = dividend - divisor;
        end

        result = quotient;
        odd = remainder;
    end

endmodule
